var TOPICS_DATA = TOPICS_DATA || {};
TOPICS_DATA["logging"] = TOPICS_DATA["logging"] || {};
TOPICS_DATA["logging"]["log-centralized"] = {"id":"log-centralized","title":"Centralized Logging","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Centralized Logging aggregates logs from multiple servers, services, and applications into a single, searchable platform for unified visibility.","Eliminates SSH'ing into individual servers to tail log files — all logs are collected, parsed, and indexed in real-time from every source.","Core components: log shippers (Filebeat, Fluentd), transport (Kafka, HTTP), processing (Logstash), storage (Elasticsearch, S3), and visualization (Kibana, Grafana).","Best practices: structured log format (JSON), include correlation IDs for distributed tracing, set retention policies, implement access controls on log data."],"laymanDefinition":"Centralized Logging is like having a security camera control room for your entire city. Instead of running to each building to check their individual tape (SSH into servers), all cameras stream to one room where you can search, filter, and spot problems anywhere instantly.","deepDive":[{"heading":"ELK Stack (Elasticsearch, Logstash, Kibana)","text":"The most popular open-source centralized logging stack. Elasticsearch: distributed search and analytics engine, stores and indexes log data. Logstash: server-side data processing pipeline, ingests from multiple sources, transforms, and sends to Elasticsearch. Kibana: visualization layer — dashboards, charts, log exploration."},{"heading":"Log Shipper Architecture","text":"Lightweight agents installed on each server: Filebeat (Elastic), Fluentd (CNCF), vector (Datadog). Shippers tail log files, add metadata (hostname, service name), and forward to a central broker (Kafka, Redis) or directly to storage. Benefits: low resource usage, buffering for network failures, encryption in transit."},{"heading":"Log Retention and Tiered Storage","text":"Hot tier: recent logs (7 days) on fast SSDs — Elasticsearch hot nodes. Warm tier: 30 days on standard HDDs. Cold tier: 90+ days on S3/Glacier — queryable but slower. Frozen tier: archive for compliance (years). Each tier trades query speed for cost. Data lifecycle management automates transitions."},{"heading":"Distributed Tracing Correlation","text":"Correlation ID (trace ID) is generated at the entry point (API gateway) and propagated through all downstream services via headers. Every log line includes this ID. Centralized logging allows searching for a single request across all services — critical for debugging microservices latency and failures."},{"heading":"Observability Beyond Logs","text":"Three pillars: logs (events), metrics (numbers), traces (request flow). Centralized logging is part of observability. Best practice: correlate logs with metrics (e.g., when error rate spikes, search logs for the failed requests). Tools: Datadog, Grafana Loki, New Relic, Honeycomb — all-in-one observability platforms."}],"interviewAnswer":"Centralized Logging is the foundation of observability in distributed systems. It replaces ad-hoc SSH debugging with a searchable, real-time view of all system events. The ELK stack is the most common self-hosted solution; Datadog and Grafana Cloud are popular SaaS alternatives. Always use structured logs (JSON) with correlation IDs for maximum value.","interviewQuestions":[{"question":"What is centralized logging?","answer":"Aggregating logs from all servers and services into a single platform for unified search, analysis, and visualization."},{"question":"What is the ELK stack?","answer":"Elasticsearch (storage/search), Logstash (processing), Kibana (visualization) — the most popular open-source centralized logging stack."},{"question":"What is a log shipper?","answer":"A lightweight agent installed on servers that tails log files and forwards them to a centralized logging platform (Filebeat, Fluentd, Vector)."},{"question":"What is a correlation ID?","answer":"A unique ID generated at the entry point and propagated through all services — allows tracing a single request across distributed systems."},{"question":"What are the three pillars of observability?","answer":"Logs (events), Metrics (numbers), Traces (request flow). Centralized logging covers the logs pillar."},{"question":"What is log retention?","answer":"How long logs are kept. Hot tier (fast SSDs, 7d), warm (HDDs, 30d), cold (S3, 90d+), frozen (archive, years)."},{"question":"What is Logstash?","answer":"A server-side data processing pipeline that ingests, transforms, and sends log data to Elasticsearch or other outputs."},{"question":"What is Kibana?","answer":"The visualization layer for Elasticsearch — dashboards, log exploration, charts, and alerting."},{"question":"What is Filebeat?","answer":"A lightweight log shipper from Elastic that tails files and forwards logs to Logstash/Elasticsearch/Kafka."},{"question":"Why use structured logs?","answer":"Parsing is automatic and reliable. JSON logs can be queried by field, unlike unstructured text that requires regex parsing."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Centralized Logging</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">App Servers</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Log sources</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"215\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Log Shippers</text><text x=\"215\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Filebeat, Fluentd</text><line x1=\"160\" y1=\"60\" x2=\"160\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"65\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Transport</text><text x=\"65\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Kafka, HTTP</text><line x1=\"120\" y1=\"83\" x2=\"150\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"70\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"215\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Processing</text><text x=\"215\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Logstash</text><line x1=\"160\" y1=\"95\" x2=\"160\" y2=\"110\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"105\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"65\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Storage</text><text x=\"65\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Elasticsearch</text><line x1=\"120\" y1=\"118\" x2=\"150\" y2=\"118\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"105\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"215\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Visualization</text><text x=\"215\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Kibana</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Centralized Logging</text><text x=\"385\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Aggregate, search, and analyze logs from all sources in one platform.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Centralized Logging: Ship, process, store, and visualize logs from every service and server.</text></svg>","codeExamples":[{"title":"Centralized Logging with Filebeat + Logstash + Elasticsearch","useCase":"Shipping logs from a Node.js app.","code":"# filebeat.yml (installed on app server)\nfilebeat.inputs:\n- type: filestream\n  paths: /var/log/myapp/*.json\n  json.keys_under_root: true\n\noutput.logstash:\n  hosts: [\"logstash:5044\"]\n\n# logstash.conf (central processing)\ninput { beats { port => 5044 } }\nfilter {\n  json { source => \"message\" }\n  mutate { remove_field => [\"message\"] }\n}\noutput {\n  elasticsearch {\n    hosts => [\"elasticsearch:9200\"]\n    index => \"myapp-%{+YYYY.MM.dd}\"\n  }\n}","description":"Filebeat ships JSON logs to Logstash for processing, then Elasticsearch for storage and indexing."},{"title":"Structured JSON Logging in Node.js","useCase":"Pino logger with correlation ID.","code":"const pino = require('pino');\nconst { v4: uuidv4 } = require('uuid');\n\nconst logger = pino({\n  level: process.env.LOG_LEVEL || 'info',\n  formatters: {\n    level(label) { return { level: label }; }\n  }\n});\n\n// Generate correlation ID per request\napp.use((req, res, next) => {\n  req.correlationId = uuidv4();\n  res.setHeader('X-Correlation-Id', req.correlationId);\n  next();\n});\n\n// Use logger with correlation ID\napp.get('/api/orders', async (req, res) => {\n  logger.info({\n    correlationId: req.correlationId,\n    path: req.path,\n    method: req.method\n  }, 'Handling order request');\n  // Or use pino-http for automatic req logging\n});","description":"Pino produces structured JSON logs. Correlation IDs link log entries across services."},{"title":"Docker Centralized Logging with Loki + Promtail + Grafana","useCase":"Lightweight alternative to ELK.","code":"# promtail.yml (log shipper for Docker)\nscrape_configs:\n- job_name: docker\n  pipeline_stages:\n  - docker: {}\n  static_configs:\n  - targets: [localhost]\n    labels:\n      job: 'myapp'\n      __path__: /var/lib/docker/containers/**/*.log\n\n# Loki (storage) runs as a single binary or Docker\n# docker run --name=loki \\\n#   -v ./loki-config.yaml:/etc/loki/loki.yaml \\\n#   grafana/loki\n\n# Grafana datasource: http://loki:3100\n# Queries: {job=\"myapp\"} |= \"error\"\n# Labels help filter quickly without indexing full text","description":"Grafana Loki is a cost-effective centralized logging system designed for Kubernetes and Docker."},{"title":"Searching Logs with Elasticsearch Query DSL","useCase":"Finding specific events.","code":"GET /myapp-2024.06.15/_search\n{\n  \"query\": {\n    \"bool\": {\n      \"must\": [\n        { \"match\": { \"level\": \"error\" } },\n        { \"match\": { \"service\": \"order-service\" } },\n        { \"range\": {\n          \"@timestamp\": {\n            \"gte\": \"now-1h\",\n            \"lte\": \"now\"\n          }\n        }}\n      ]\n    }\n  },\n  \"aggs\": {\n    \"errors_by_minute\": {\n      \"date_histogram\": {\n        \"field\": \"@timestamp\",\n        \"interval\": \"1m\"\n      }\n    }\n  }\n}","description":"Elasticsearch query DSL enables powerful filtering, aggregation, and analysis of log data."},{"title":"Fluentd Configuration for Centralized Logging","useCase":"Unified logging layer.","code":"# fluentd.conf\n<source>\n  @type tail\n  path /var/log/myapp/*.log\n  format json\n  tag myapp\n</source>\n\n<filter myapp.**>\n  @type record_transformer\n  <record>\n    hostname \"#{Socket.gethostname}\"\n    environment \"#{ENV['NODE_ENV']}\"\n  </record>\n</filter>\n\n<match myapp.**>\n  @type elasticsearch\n  host elasticsearch\n  port 9200\n  logstash_format true\n  <buffer>\n    @type file\n    path /var/log/fluentd/buffer\n    retry_max_times 5\n  </buffer>\n</match>","description":"Fluentd provides a unified logging layer with buffering, filtering, and multiple output plugins."}],"mcqQuestions":[{"question":"What problem does centralized logging solve?","options":["SSD space management","Needing to SSH into servers to read logs","Network latency","Load balancing"],"answer":1,"explanation":"Centralized logging eliminates the need to manually access each server to check logs."},{"question":"What does the E in ELK stack stand for?","options":["Elasticsearch","Express","EC2","Ember"],"answer":0,"explanation":"ELK = Elasticsearch, Logstash, Kibana."},{"question":"What is a log shipper?","options":["A tool that visualizes logs","An agent that forwards logs from servers","A database for logs","A log parser"],"answer":1,"explanation":"Log shippers like Filebeat and Fluentd are lightweight agents that forward logs."},{"question":"What is a correlation ID used for?","options":["Counting errors","Tracing a request across distributed services","Billing","Load balancing"],"answer":1,"explanation":"Correlation IDs link log entries from the same request across multiple services."},{"question":"What is the hot tier in log storage?","options":["Nearline archive","Recent logs on fast storage","Compressed backup","S3 storage"],"answer":1,"explanation":"Hot tier stores recent logs on fast SSDs for quick querying; older data moves to cheaper storage."},{"question":"What are the three pillars of observability?","options":["Dev, Staging, Prod","Logs, Metrics, Traces","CPU, Memory, Disk","Build, Test, Deploy"],"answer":1,"explanation":"Observability consists of logs (events), metrics (numbers), and traces (request flow)."},{"question":"Centralized Logging — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Centralized Logging — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Centralized Logging — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Centralized Logging — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["logging"]["log-structured"] = {"id":"log-structured","title":"Structured Logging","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Structured logging outputs log entries as structured data (JSON) instead of plain text, making them machine-parseable and queryable.","Each log entry has named fields: timestamp, level, message, service, correlationId, duration, userId. No regex parsing needed to extract values.","Benefits: automatic parsing by log platforms, rich filtering and aggregation, consistent schema across services, easy integration with alerting systems.","Standard fields: @timestamp (ISO 8601), level (error/warn/info/debug), logger (class/module name), message (human-readable), and custom context fields."],"laymanDefinition":"Structured logging is like filling out a standardized form instead of writing a paragraph. A form has named fields: \"Date:\", \"Customer:\", \"Issue:\". You can instantly search all forms for \"Customer: Alice\". Unstructured logging is like a diary entry: \"Today Alice came in with a problem, it happened around 3 PM.\" Harder to search and analyze.","deepDive":[{"heading":"JSON Log Format","text":"{\"@timestamp\": \"2024-06-15T10:30:00Z\", \"level\": \"error\", \"logger\": \"UserService\", \"message\": \"Failed to create user\", \"userId\": 42, \"error\": {\"code\": \"DUPLICATE_EMAIL\", \"stack\": \"...\"}}. Benefits: parsers can index each field, dashboards can aggregate by level, alerts can trigger on specific conditions."},{"heading":"Log Levels in Structured Logging","text":"trace: detailed debugging (development only). debug: diagnostic info for troubleshooting. info: normal application events (request started, user created). warn: unexpected but handled issues (rate limit exceeded). error: failures requiring attention (DB connection lost). fatal: unrecoverable errors (process exit)."},{"heading":"Contextual Logging (Child Loggers)","text":"Create child loggers pre-populated with context: const childLogger = logger.child({ service: \\'orders\\', requestId: req.id }). Every log from this child automatically includes service and requestId fields. Eliminates repetitive manual field injection. Patterns: per-request child logger in middleware, per-service child logger at startup."},{"heading":"Structured Logging in Microservices","text":"Every service logs structured JSON to stdout. Log shippers (Filebeat, Fluentd) collect from all services. Centralized platform indexes by service name field. Search across all services: {service: \"orders\"} AND level: \"error\". Correlation IDs connect entries across services. Consistent schema across teams via shared logging library."},{"heading":"Performance Considerations","text":"Structured logging is slightly slower than plain text due to serialization overhead. Mitigations: async logging (worker thread), batching, sampling high-volume debug logs, choose fast JSON serializers (pino is faster than bunyan/winston). Pino claims ~5x faster than Winston due to minimal serialization overhead."}],"interviewAnswer":"Structured logging is essential for any production system. Use JSON format with a consistent schema. Include correlation IDs, service names, and relevant context. Pino is the fastest Node.js logger. Send all logs to stdout and use a log shipper — never write to files directly in containerized environments. Structured logs are the foundation of observability.","interviewQuestions":[{"question":"What is structured logging?","answer":"Outputting log entries as structured data (JSON) with named fields instead of unstructured plain text."},{"question":"Why use structured logging?","answer":"Machine-parseable, queryable by field, consistent schema, no regex parsing, easier integration with log platforms."},{"question":"What is a child logger?","answer":"A logger pre-populated with context fields. Every log from the child automatically includes those fields."},{"question":"What are common structured log fields?","answer":"@timestamp, level, message, logger (module/class), service, correlationId, userId, duration, error."},{"question":"What is the fastest Node.js logger?","answer":"Pino — ~5x faster than Winston due to minimal serialization overhead and async design."},{"question":"What log levels exist?","answer":"trace, debug, info, warn, error, fatal. Use info for normal events, error for failures, trace/debug for development."},{"question":"Should you log to files in Docker?","answer":"No. Log to stdout. Docker captures stdout/stderr. A log shipper collects from Docker\\'s log driver."},{"question":"What is log level sampling?","answer":"Logging only a percentage of high-volume events (e.g., 1% of debug logs) to reduce volume while retaining signal."},{"question":"How do you add context to logs?","answer":"Use child loggers, pass context object to each log call, or use AsyncLocalStorage for automatic context propagation."},{"question":"What is the schema consistency problem?","answer":"Different services may log the same field with different names/types. Solve with a shared logging library/schema registry."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Structured Logging</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Plain Text</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">\"User logged in\"</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"225\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Parsing Hell</text><text x=\"225\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">regex, grep, cut</text><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">JSON Format</text><text x=\"65\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">{\"level\":\"info\",\"userId\":42}</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"65\" width=\"130\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"225\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Auto-Parsed</text><text x=\"225\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Query by field</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Child Logger</text><text x=\"65\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Pre-populated context</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Pino Logger</text><text x=\"65\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Fast serialization</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Correlation ID</text><text x=\"65\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Trace across services</text><rect x=\"300\" y=\"35\" width=\"180\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"390\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Structured Logging</text><text x=\"390\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">JSON logs with named fields. Machine-parseable, queryable, consistent across services.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Structured Logging: JSON-formatted logs with named fields — no regex, instant querying, rich analysis.</text></svg>","codeExamples":[{"title":"Pino Structured Logger (Node.js)","useCase":"Fast JSON logging.","code":"const pino = require('pino');\n\nconst logger = pino({\n  level: process.env.LOG_LEVEL || 'info',\n  timestamp: pino.stdTimeFunctions.isoTime,\n  formatters: {\n    bindings(bindings) {\n      return { pid: bindings.pid, host: bindings.hostname };\n    }\n  },\n  redact: {\n    paths: ['req.headers.authorization', 'req.body.password'],\n    censor: '[REDACTED]'\n  }\n});\n\nlogger.info({ userId: 42, action: 'create_order' }, 'Order created');\n// {\"level\":30,\"time\":\"2024-06-15T10:30:00Z\",\n//  \"pid\":1234,\"host\":\"server1\",\n//  \"userId\":42,\"action\":\"create_order\",\n//  \"msg\":\"Order created\"}","description":"Pino outputs structured JSON with automatic timestamp, level, and custom context fields."},{"title":"Winston Structured Logger (Node.js)","useCase":"Popular alternative with transports.","code":"const winston = require('winston');\n\nconst logger = winston.createLogger({\n  level: 'info',\n  format: winston.format.combine(\n    winston.format.timestamp(),\n    winston.format.errors({ stack: true }),\n    winston.format.json()\n  ),\n  defaultMeta: { service: 'order-service' },\n  transports: [\n    new winston.transports.Console(),\n    new winston.transports.File({\n      filename: 'logs/error.log', level: 'error'\n    })\n  ]\n});\n\nlogger.error('Database connection failed', {\n  dbHost: process.env.DB_HOST,\n  retryAttempt: 3\n});","description":"Winston provides flexible transports and formatting with structured JSON output."},{"title":"Child Logger with Request Context","useCase":"Automatic context via middleware.","code":"// Middleware: create child logger per request\napp.use((req, res, next) => {\n  req.log = logger.child({\n    requestId: uuidv4(),\n    method: req.method,\n    url: req.url,\n    ip: req.ip\n  });\n  next();\n});\n\n// Route handler — no repetitive context injection\napp.get('/api/users/:id', async (req, res) => {\n  req.log.info({ userId: req.params.id }, 'Fetching user');\n  try {\n    const user = await db.findUser(req.params.id);\n    req.log.info('User found');\n    res.json(user);\n  } catch (err) {\n    req.log.error({ err }, 'Failed to fetch user');\n    res.status(500).json({ error: 'Internal error' });\n  }\n});","description":"Child loggers automatically include request context in every log entry without manual injection."},{"title":"Structured Error Logging with Stack Traces","useCase":"Log full error details.","code":"const pino = require('pino');\n\nconst logger = pino({\n  serializers: {\n    err: pino.stdSerializers.err,\n    req: pino.stdSerializers.req,\n    res: pino.stdSerializers.res\n  }\n});\n\ntry {\n  throw new Error('Database timeout');\n} catch (err) {\n  // Automatically serializes: message, stack, type\n  logger.error({ err, query: 'SELECT * FROM orders' },\n    'Query failed');\n  // {\"level\":50,\"err\":{\"type\":\"Error\",\n  //  \"message\":\"Database timeout\",\n  //  \"stack\":\"Error: Database timeout\\n at ...\"},\n  //  \"query\":\"SELECT * FROM orders\"}\n}","description":"Error serializers capture full stack traces and error details in structured format."},{"title":"AsyncLocalStorage for Automatic Context","useCase":"No need to pass logger through every function.","code":"const { AsyncLocalStorage } = require('async_hooks');\nconst asyncStore = new AsyncLocalStorage();\n\nconst baseLogger = require('pino')();\n\napp.use((req, res, next) => {\n  const store = {\n    logger: baseLogger.child({\n      requestId: uuidv4(),\n      userId: req.user?.id\n    })\n  };\n  asyncStore.run(store, () => next());\n});\n\nfunction getLogger() {\n  return asyncStore.getStore()?.logger || baseLogger;\n}\n\n// In any service layer:\nasync function createOrder(data) {\n  const log = getLogger();\n  log.info({ data }, 'Creating order');\n  // No need to pass req.log through calls\n}","description":"AsyncLocalStorage propagates the logger context automatically without passing it through parameters."}],"mcqQuestions":[{"question":"What format does structured logging use?","options":["CSV","JSON","XML","YAML"],"answer":1,"explanation":"Structured logging most commonly uses JSON format with named fields."},{"question":"Which Node.js logger is fastest?","options":["Winston","Bunyan","Pino","Log4js"],"answer":2,"explanation":"Pino is significantly faster due to minimal serialization overhead."},{"question":"What is a child logger?","options":["A logger for children","A logger with pre-populated context fields","A separate log file","A logger that filters by level"],"answer":1,"explanation":"Child loggers inherit parent configuration and add predefined context fields automatically."},{"question":"What should be included in every log?","options":["@timestamp, level, message","IP address only","Server uptime","Memory usage"],"answer":0,"explanation":"Every structured log should include timestamp, level, and a descriptive message plus relevant context."},{"question":"Why log to stdout in containers?","options":["Better performance","Docker captures stdout; shippers collect from Docker","It is the default","Files are not allowed"],"answer":1,"explanation":"Docker and Kubernetes capture stdout/stderr; using stdout is the container-native logging pattern."},{"question":"What log level indicates failure?","options":["info","warn","error","debug"],"answer":2,"explanation":"Error level indicates a failure that needs investigation. Fatal indicates unrecoverable errors."},{"question":"Structured Logging — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Structured Logging — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Structured Logging — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Structured Logging — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["logging"]["log-aggregation"] = {"id":"log-aggregation","title":"Log Aggregation","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Log aggregation is the process of collecting, processing, and storing logs from multiple sources into a centralized repository for analysis and alerting.","Unlike simple centralized logging, aggregation adds enrichment, normalization, deduplication, and transformation pipelines to make raw logs useful.","Key stages: collection (shippers), buffering (Kafka/Redis), transformation (Logstash/Fluentd), enrichment (add geoip, user context), storage (Elasticsearch/S3), and querying.","Aggregation pipelines can parse unstructured logs into structured fields, redact sensitive data, filter noisy logs, and route different log types to different destinations."],"laymanDefinition":"Log aggregation is like a postal sorting facility. Raw mail (logs) arrives from every mailbox in the city (servers). Workers sort by zip code (normalize), remove junk (filter), add tracking numbers (enrich), bundle for each route (buffer), and deliver to the right destination (storage). Without the sorting facility, each mailbox would be a chaotic pile.","deepDive":[{"heading":"Collection and Buffering Layer","text":"Shippers (Filebeat, Fluentbit) collect logs and send to a buffer (Kafka, Redis, or NATS). Buffers absorb traffic spikes, provide replay capability, and decouple producers from consumers. Kafka is preferred for high-volume production: partitioning by log source, replication for durability, retention for replay."},{"heading":"Transformation Pipelines","text":"Logstash or Fluentd process raw logs: parse unstructured text into JSON (grok patterns), normalize field names (host -> hostname), add metadata (geoip from IP), filter sensitive data (credit cards, passwords), drop noisy debug logs, route error logs to separate index. Pipeline stages: input -> filter -> output."},{"heading":"Enrichment Strategies","text":"GeoIP: add latitude/longitude/country from IP address. User context: add username, role from session/token. Service topology: add service version, deployment environment. Threat intelligence: cross-reference IPs with known threat feeds. Enrichment happens in the pipeline before storage."},{"heading":"Aggregation Architecture Patterns","text":"Push model: shippers push to central ingester (simpler, common). Pull model: central collector pulls from agents (better for firewalls). Agentless: servers send logs directly via syslog/HTTP (no agent install). Hybrid: agents for production, agentless for legacy systems. Choose based on security requirements and network topology."},{"heading":"Alerting from Aggregated Logs","text":"Define alert rules on aggregated data: error rate > X% in 5 minutes, no logs from a service for 10 minutes, specific error pattern detected. Tools: ElastAlert (Elasticsearch), Grafana alerts (Loki), Kibana alerting. Severity levels: critical (page on-call), warning (create ticket), info (log for trend analysis)."}],"interviewAnswer":"Log aggregation transforms raw, noisy logs into actionable data. Design your pipeline carefully: buffering prevents data loss, transformation normalizes the schema, enrichment adds business context, and alerting turns logs into automated responses. Start simple with Filebeat + Elasticsearch, add Kafka at scale, and evolve into a full observability platform.","interviewQuestions":[{"question":"What is log aggregation?","answer":"Collecting, processing, enriching, and storing logs from multiple sources into a centralized, queryable repository."},{"question":"What is the role of Kafka in log aggregation?","answer":"Acts as a durable buffer — decouples log producers from consumers, absorbs traffic spikes, enables replay."},{"question":"What is grok in Logstash?","answer":"A pattern-matching syntax to parse unstructured log lines into structured fields using regex-like patterns."},{"question":"What is log enrichment?","answer":"Adding contextual data (geoip, user info, environment) to log entries during pipeline processing."},{"question":"What is a log pipeline?","answer":"The end-to-end flow: collection -> buffering -> transformation -> enrichment -> storage -> querying."},{"question":"What is the difference between push and pull log collection?","answer":"Push: agents send logs to central server (simpler). Pull: central server fetches from agents (better firewall traversal)."},{"question":"What is deduplication in log aggregation?","answer":"Removing duplicate log entries. Useful when the same event is logged by multiple sources or retries cause repeats."},{"question":"What is log normalization?","answer":"Converting logs from different sources into a consistent schema (same field names, types, and formats)."},{"question":"What is ElastAlert?","answer":"An open-source alerting framework for Elasticsearch data — triggers alerts based on configurable rules."},{"question":"Why buffer logs before processing?","answer":"Buffers handle traffic spikes, prevent data loss if downstream is unavailable, and allow replay of failed processing."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Log Aggregation</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Sources</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Apps, servers</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"200\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Shippers</text><text x=\"200\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Filebeat, Fluentd</text><line x1=\"150\" y1=\"60\" x2=\"150\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Buffer</text><text x=\"60\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Kafka, Redis</text><line x1=\"110\" y1=\"83\" x2=\"140\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"200\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Transform</text><text x=\"200\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Parse, normalize</text><line x1=\"150\" y1=\"95\" x2=\"150\" y2=\"110\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"60\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Enrich</text><text x=\"60\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">GeoIP, context</text><line x1=\"110\" y1=\"118\" x2=\"140\" y2=\"118\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"200\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Store</text><text x=\"200\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Elasticsearch, S3</text><rect x=\"270\" y=\"35\" width=\"210\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"375\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Log Aggregation</text><text x=\"375\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Ship -> Buffer -> Transform -> Enrich -> Store -> Alert. Raw logs become actionable data.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Log Aggregation: Pipeline that transforms raw, noisy logs into structured, actionable, enriched data.</text></svg>","codeExamples":[{"title":"Logstash Grok Parsing (Apache Logs)","useCase":"Parse unstructured logs into fields.","code":"# Input: 192.168.1.1 - - [15/Jun/2024:10:30:00 +0000] \"GET /api/users 200\" 1234 \"Mozilla/5.0\"\n\nfilter {\n  grok {\n    match => { \"message\" => [\n      \"%{IP:client_ip} - - \\[%{HTTPDATE:timestamp}\\]\n      \\\"%{WORD:method} %{URIPATHPARAM:request}\n      %{NUMBER:status_code}\\\" %{NUMBER:bytes}\n      \\\"%{GREEDYDATA:user_agent}\\\"\n    ] }\n  }\n  date {\n    match => [\"timestamp\", \"dd/MMM/yyyy:HH:mm:ss Z\"]\n    target => \"@timestamp\"\n  }\n  geoip { source => \"client_ip\" }\n  useragent { source => \"user_agent\" }\n  mutate { remove_field => [\"message\"] }\n}","description":"Grok pattern parses Apache logs into structured fields with geoip and user agent enrichment."},{"title":"Kafka as Log Buffer (Docker Compose)","useCase":"Durable log transport.","code":"version: '3'\nservices:\n  zookeeper:\n    image: confluentinc/cp-zookeeper:latest\n    environment:\n      ZOOKEEPER_CLIENT_PORT: 2181\n\n  kafka:\n    image: confluentinc/cp-kafka:latest\n    depends_on: [zookeeper]\n    environment:\n      KAFKA_ZOOKEEPER_CONNECT: zookeeper:2181\n      KAFKA_ADVERTISED_LISTENERS: PLAINTEXT://kafka:9092\n      KAFKA_TOPIC_LOG_RETENTION_MS: 604800000\n\n  logstash:\n    image: docker.elastic.co/logstash/logstash:8.12.0\n    environment:\n      LS_JAVA_OPTS: '-Xmx1g -Xms1g'\n    volumes:\n      - ./logstash.conf:/usr/share/logstash/pipeline/logstash.conf","description":"Kafka buffers logs between shippers and Logstash, providing durability and replay capability."},{"title":"Fluentd Aggregation Pipeline","useCase":"Unified log processing.","code":"## Source: tail JSON logs\n<source>\n  @type tail\n  format json\n  path /var/log/app/*.log\n  tag app.log\n</source>\n\n## Filter: add environment and hostname\n<filter app.log>\n  @type record_transformer\n  <record>\n    env \"#{ENV['NODE_ENV'] || 'development'}\"\n    hostname ${hostname}\n  </record>\n</filter>\n\n## Filter: redact sensitive data\n<filter app.log>\n  @type grep\n  exclude1 message .*password.*\n</filter>\n\n## Output: route errors to separate index\n<match app.log>\n  @type elasticsearch\n  host elasticsearch:9200\n  include_tag_key true\n  <buffer>\n    @type file\n    path /var/log/fluentd-buffer\n  </buffer>\n</match>","description":"Fluentd pipeline: tail logs -> add metadata -> redact sensitive data -> buffer -> Elasticsearch."},{"title":"Log Aggregation with AWS CloudWatch + Lambda","useCase":"Serverless log processing.","code":"# CloudWatch Logs subscription filter\n# Sends matching logs to Lambda for processing\n\nexports.handler = async (event) => {\n  const logs = event.awslogs.data;\n  const decoded = Buffer.from(logs, 'base64');\n  const parsed = JSON.parse(decoded.toString());\n\n  for (const logEvent of parsed.logEvents) {\n    const entry = JSON.parse(logEvent.message);\n    \n    // Enrich with additional context\n    entry.environment = process.env.ENV;\n    entry.processedAt = new Date().toISOString();\n\n    // Route to Elasticsearch or S3\n    if (entry.level === 'error') {\n      await sendToElasticsearch(entry);\n      await sendToAlerting(entry);\n    } else {\n      await sendToS3(entry);\n    }\n  }\n};","description":"CloudWatch Logs subscription with Lambda enables serverless log aggregation and enrichment."},{"title":"Log Deduplication and Rate Limiting","useCase":"Reduce noisy logs.","code":"// Logstash filter: deduplicate similar errors\nfilter {\n  fingerprint {\n    source => [\"message\", \"level\", \"file\"]\n    target => \"[@metadata][fingerprint]\"\n    method => \"SHA256\"\n  }\n}\n\n// Rate limit: max 5 identical errors per minute\nfilter {\n  throttle {\n    before_count => -1\n    after_count => 5\n    period => 60\n    max_age => 86400\n    key => \"%{[@metadata][fingerprint]}\"\n    add_tag => [\"throttled\"]\n  }\n}\n\n// Drop throttled events in output\noutput {\n  if \"throttled\" not in [tags] {\n    elasticsearch { ... }\n  }\n}","description":"Deduplication and rate limiting prevent log floods from overwhelming storage and alerting systems."}],"mcqQuestions":[{"question":"What does a log aggregation pipeline include?","options":["Collection, buffer, transform, enrich, store","Only collection","Only storage","Only visualization"],"answer":0,"explanation":"A full pipeline includes collection, buffering, transformation, enrichment, and storage."},{"question":"What is the role of Kafka in log aggregation?","options":["Visualization","Durable buffering and decoupling","Log parsing","Alert generation"],"answer":1,"explanation":"Kafka acts as a durable buffer that decouples log producers from consumers."},{"question":"What is grok used for?","options":["Compressing logs","Parsing unstructured logs into fields","Encrypting logs","Routing logs"],"answer":1,"explanation":"Grok is a pattern-matching system in Logstash for parsing unstructured log lines."},{"question":"What is log enrichment?","options":["Deleting old logs","Adding context data to log entries","Compressing log files","Changing log format"],"answer":1,"explanation":"Enrichment adds contextual data like geoip, user information, or environment metadata."},{"question":"What is the advantage of buffering logs?","options":["Faster querying","Handles traffic spikes, prevents data loss","Smaller storage","Better visualization"],"answer":1,"explanation":"Buffers absorb spikes, provide replay capability, and prevent data loss during downstream outages."},{"question":"What does log normalization do?","options":["Normalizes file permissions","Converts logs to a consistent schema","Normalizes log file sizes","Normalizes server time"],"answer":1,"explanation":"Normalization converts logs from different sources into a consistent field schema."},{"question":"Log Aggregation — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Log Aggregation — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Log Aggregation — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Log Aggregation — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["logging"]["log-rotation"] = {"id":"log-rotation","title":"Log Rotation","difficulty":"beginner","estimatedMinutes":10,"tldr":["Log rotation is the process of archiving, compressing, or deleting old log files to prevent disk space exhaustion while preserving recent logs for debugging.","Without rotation, a single log file grows indefinitely — filling the disk, crashing the application, and making log analysis impractical (gigabyte-sized files).","Key parameters: max file size (100MB), max age (30 days), max files (10), compression (gzip), naming pattern (app.log -> app.2024-06-15.log.gz).","Rotation strategies: size-based (rotate when file exceeds N MB), time-based (rotate daily/hourly), hybrid (rotate on first trigger)."],"laymanDefinition":"Log rotation is like having a self-cleaning notebook. When a page fills up, you tear it out, file it in a labeled folder (archive), and start a fresh page. When the filing cabinet fills up, you shred the oldest folders (delete). Without this, the notebook keeps growing until it bursts the binder and covers your desk in paper.","deepDive":[{"heading":"Linux logrotate Tool (Standard)","text":"The standard log rotation tool for Linux servers. Configuration files in /etc/logrotate.d/. Supports: size threshold, daily/weekly/monthly rotation, compression (gzip), post-rotation scripts (restart service, signal application), date-based naming, max number of rotated files. Cron job runs logrotate daily."},{"heading":"Size-Based vs Time-Based Rotation","text":"Size-based: rotate when file exceeds threshold (100MB). Good for high-volume apps with predictable log rates. Time-based: rotate every N hours/days. Predictable archive naming, easier to correlate with time periods. Hybrid: rotate on whichever triggers first. Recommended: size-based with max age as safety net."},{"heading":"Compression and Archiving","text":"Gzip rotated logs: reduces size by 80-90%. Trade-off: cannot search compressed logs without decompression. Strategies: compress after N days, keep last N uncompressed for quick debugging, archive to cold storage (S3/Glacier) after retention period. Use pigz (parallel gzip) for faster compression of large files."},{"heading":"Application-Level Rotation (Log4j/Winston)","text":"Some logging libraries support rotation internally (Log4j\\'s RollingFileAppender, Winston\\'s File transport with maxsize). Benefits: no external tool needed, application-controlled naming, programmatic configuration. Drawbacks: application crash during rotation can lose data. Recommended: use system-level logrotate for production, app-level as fallback."},{"heading":"Docker/Kubernetes Log Rotation","text":"Docker uses json-file logging driver by default — rotates via max-size and max-file flags. Kubernetes: kubelet handles log rotation (max 10 files, 10MB each by default). In Kubernetes, sidecar containers with log shippers (Fluentbit) provide more control. Best practice: containers log to stdout, let the runtime handle rotation."}],"interviewAnswer":"Log rotation is a simple but critical operational practice. Always configure rotation before deploying to production — a disk-full crash from unrotated logs is embarrassing and preventable. Use logrotate on Linux, configure Docker's max-size/max-file, and set retention policies. Compress old logs but keep recent ones uncompressed for quick grep access.","interviewQuestions":[{"question":"What is log rotation?","answer":"Archiving, compressing, or deleting old log files to prevent disk space exhaustion while retaining recent logs for debugging."},{"question":"Why is log rotation important?","answer":"Without it, log files grow indefinitely — filling disks, crashing apps, and making analysis impractical."},{"question":"What is the Linux logrotate tool?","answer":"The standard log rotation utility for Linux — configured in /etc/logrotate.d/ with cron-based execution."},{"question":"What are common rotation triggers?","answer":"File size (100MB), time interval (daily), or hybrid (first trigger)."},{"question":"What is gzip compression in log rotation?","answer":"Compresses rotated logs (80-90% size reduction). Recent logs kept uncompressed for quick searching."},{"question":"How does Docker handle log rotation?","answer":"Via json-file logging driver options: --log-opt max-size=10m --log-opt max-file=3."},{"question":"How does Kubernetes handle log rotation?","answer":"kubelet rotates logs automatically (default: 10 files, 10MB each). Use sidecar containers for more control."},{"question":"What is a post-rotation script?","answer":"A command run after rotation (logrotate: postrotate/endscript). Used to restart services or send SIGHUP."},{"question":"What is the dateext option in logrotate?","answer":"Adds date to rotated filenames instead of sequential numbers: app.log -> app-20240615.gz."},{"question":"How many rotated logs should you keep?","answer":"Depends on retention policy. Common: 30 daily logs (1 month) or 7 daily + 4 weekly (rolling month)."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Log Rotation</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">app.log</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Active file</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"215\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Size Exceeded</text><text x=\"215\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">100MB threshold</text><line x1=\"160\" y1=\"60\" x2=\"160\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"65\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Rotate</text><text x=\"65\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Rename + compress</text><line x1=\"120\" y1=\"83\" x2=\"150\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"70\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"215\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">app.1.log.gz</text><text x=\"215\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Archived</text><rect x=\"10\" y=\"105\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"65\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">New app.log</text><text x=\"65\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Fresh file</text><rect x=\"10\" y=\"135\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"65\" y=\"151\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Delete Oldest</text><text x=\"65\" y=\"163\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Retention limit</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Log Rotation</text><text x=\"385\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Prevent disk-full crashes. Archive, compress, and purge old logs automatically.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Log Rotation: Automatically archive, compress, and delete old log files to manage disk space.</text></svg>","codeExamples":[{"title":"Linux logrotate Configuration","useCase":"Standard rotation setup.","code":"# /etc/logrotate.d/myapp\n/var/log/myapp/*.log {\n    daily\n    rotate 30\n    size 100M\n    compress\n    delaycompress\n    missingok\n    notifempty\n    dateext\n    postrotate\n        systemctl reload myapp 2>/dev/null || true\n    endscript\n}\n\n# Options explained:\n# daily: rotate every day\n# rotate 30: keep 30 rotated files\n# size 100M: also rotate if file > 100MB\n# compress: gzip rotated files\n# delaycompress: skip compressing the most recent\n#   rotated file (easier to debug)\n# missingok: no error if log file missing\n# dateext: use date in filename (app-20240615.gz)","description":"logrotate configuration for a typical application — hybrid size+time rotation with compression."},{"title":"Docker Container Log Rotation","useCase":"Prevent Docker logs from filling disk.","code":"# Option 1: docker run flags\ndocker run \\\n  --log-driver json-file \\\n  --log-opt max-size='10m' \\\n  --log-opt max-file='3' \\\n  myapp\n\n# Option 2: Docker Compose\nservices:\n  myapp:\n    image: myapp\n    logging:\n      driver: json-file\n      options:\n        max-size: '10m'\n        max-file: '3'\n\n# Option 3: Global daemon.json\n# /etc/docker/daemon.json\n{ \"log-driver\": \"json-file\",\n  \"log-opts\": {\n    \"max-size\": \"10m\",\n    \"max-file\": \"3\"\n  }\n}","description":"Docker log rotation prevents containers from filling disk with log files."},{"title":"Winston File Rotation (Node.js)","useCase":"Application-level rotation.","code":"const winston = require('winston');\nrequire('winston-daily-rotate-file');\n\nconst transport = new winston.transports.DailyRotateFile({\n  filename: 'logs/application-%DATE%.log',\n  datePattern: 'YYYY-MM-DD',\n  maxSize: '100m',\n  maxFiles: '30d',\n  zippedArchive: true,\n  format: winston.format.combine(\n    winston.format.timestamp(),\n    winston.format.json()\n  )\n});\n\ntransport.on('rotate', (oldFilename, newFilename) => {\n  console.log('Log rotated:', oldFilename, '->', newFilename);\n});\n\nconst logger = winston.createLogger({\n  transports: [transport]\n});","description":"Winston daily rotation with size limit, 30-day retention, and automatic gzip compression."},{"title":"Manual Log Rotation Script (Bash)","useCase":"Simple rotation for any app.","code":"#!/bin/bash\nLOG_FILE=\"/var/log/myapp/app.log\"\nMAX_SIZE=104857600  # 100MB in bytes\nRETENTION_DAYS=30\n\n# Check file size\nif [ -f \"$LOG_FILE\" ] && [ $(stat -c%s \"$LOG_FILE\") -gt $MAX_SIZE ]; then\n  # Rotate: rename with timestamp\n  TIMESTAMP=$(date +%Y%m%d-%H%M%S)\n  mv \"$LOG_FILE\" \"${LOG_FILE}.${TIMESTAMP}\"\n\n  # Reopen log file (send SIGHUP if app supports it)\n  kill -HUP $(cat /var/run/myapp.pid) 2>/dev/null\n\n  # Compress old log\n  gzip \"${LOG_FILE}.${TIMESTAMP}\" &\n\n  # Delete logs older than retention period\n  find /var/log/myapp -name \"*.gz\" -mtime +$RETENTION_DAYS -delete\nfi","description":"Simple manual log rotation script that checks size, rotates, compresses, and purges old logs."},{"title":"Kubernetes Log Rotation Config","useCase":"Pod-level log management.","code":"# Node-level kubelet config\n# /var/lib/kubelet/config.yaml\ncontainerLogMaxSize: \"10Mi\"\ncontainerLogMaxFiles: 5\n\n# Or use a sidecar with log rotation\napiVersion: v1\nkind: Pod\nmetadata:\n  name: myapp\nspec:\n  containers:\n  - name: app\n    image: myapp\n    volumeMounts:\n    - name: logs\n      mountPath: /var/log/app\n  - name: log-rotator\n    image: tutt/rotate:latest\n    volumeMounts:\n    - name: logs\n      mountPath: /var/log/app\n  volumes:\n  - name: logs\n    emptyDir: {}","description":"Kubernetes log rotation via kubelet config or sidecar container pattern."}],"mcqQuestions":[{"question":"What problem does log rotation solve?","options":["Log format consistency","Disk space exhaustion from unbounded log growth","Log encryption","Log query speed"],"answer":1,"explanation":"Log rotation prevents log files from growing until they fill the disk and crash the application."},{"question":"What is the Linux tool for log rotation?","options":["cron","logrotate","rsyslog","systemd"],"answer":1,"explanation":"logrotate is the standard Linux utility for automated log rotation."},{"question":"What does the compress option in logrotate do?","options":["Deletes old logs","Gzips rotated logs","Encrypts logs","Splits logs"],"answer":1,"explanation":"compress applies gzip compression to rotated log files, reducing size by ~80-90%."},{"question":"How does Docker control log rotation?","options":["Via Dockerfile","Via --log-opt max-size and max-file","Via docker-compose.yml only","Automatically"],"answer":1,"explanation":"Docker log rotation is configured with max-size and max-file logging options."},{"question":"What is a post-rotation script?","options":["Script to analyze logs","Script run after logrotate finishes","Script to delete logs","Script to create logs"],"answer":1,"explanation":"Post-rotation scripts typically reload or restart the application to reopen log file handles."},{"question":"What is the default Kubernetes log rotation?","options":["No rotation","10 files, 10MB each (configurable)","Daily rotation","Size-based only"],"answer":1,"explanation":"kubelet rotates logs by default with configurable max size and max file count."},{"question":"Log Rotation — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Log Rotation — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Log Rotation — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Log Rotation — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["logging"]["log-levels"] = {"id":"log-levels","title":"Log Levels","difficulty":"beginner","estimatedMinutes":10,"tldr":["Log levels categorize log entries by severity, allowing developers to filter noise from critical issues and control verbosity in different environments.","Standard hierarchy (most to least severe): fatal, error, warn, info, debug, trace. Each level includes all levels above it (info includes warn, error, fatal).","Environment recommendations: production = info (capture errors + normal events), staging = debug, development = trace. Never leave debug/trace on in production at high volume.","Log levels enable: alerting only on error/fatal, suppressing debug in production, gradually increasing verbosity for troubleshooting specific components."],"laymanDefinition":"Log levels are like volume knobs on a radio. Fatal/Error is the emergency broadcast system — you stop everything to listen. Warn is the weather alert. Info is the regular news. Debug is the detailed sports commentary. Trace is the static between stations — useful to engineers, noise to everyone else. You turn the knob up (more verbose) when troubleshooting.","deepDive":[{"heading":"Standard Log Levels (RFC 5424)","text":"Syslog severity levels (0-7): Emergency (0) — system unusable. Alert (1) — immediate action required. Critical (2) — critical condition. Error (3) — error condition. Warning (4) — warning condition. Notice (5) — normal but significant. Informational (6) — general info. Debug (7) — debug-level messages. Most apps use error/warn/info/debug."},{"heading":"Choosing the Right Level","text":"Fatal: app cannot continue (cannot connect to DB on startup). Error: operation failed (payment declined, DB query failed). Warn: unexpected but handled (rate limit hit, retry succeeded, deprecated API used). Info: significant lifecycle events (server started, user registered, order placed). Debug: detailed diagnostic info (SQL queries, API response times). Trace: step-by-step execution flow (entering/exiting functions)."},{"heading":"Environment-Based Level Configuration","text":"Production: info (or warn for high-volume apps). Covers error/warn/info. Filter debug/trace. Staging: debug for troubleshooting test failures. Development: trace for maximum verbosity. Configure via environment variable (LOG_LEVEL=info). Change log level at runtime for specific components without restart using dynamic configuration."},{"heading":"Dynamic Log Level Changing","text":"Change log level at runtime without restarting the process. Useful for: temporarily enabling debug on a production service to diagnose an issue. Implementation: shared configuration store (Redis, config server), HTTP endpoint to change level (/loglevel), signal handling (SIGUSR2). Log level reverts to default on restart."},{"heading":"Per-Component Log Levels","text":"Different log levels for different modules or packages. Example: set db module to debug, http module to warn, and everything else to info. Node.js: pino supports level per child logger. Winston: level per transport. Benefits: reduce noise from well-known components, increase detail on components being investigated."}],"interviewAnswer":"Log levels are your first line of defense against log noise. Set the right level for each message: error for actual failures, warn for surprises that are handled, info for significant events, debug for diagnostics. Configure levels per environment and consider per-component levels. Implement dynamic log level changes for production debugging without restarting services.","interviewQuestions":[{"question":"What are log levels?","answer":"Severity categories for log entries: fatal, error, warn, info, debug, trace. Higher levels include all lower levels."},{"question":"What log level should production use?","answer":"Info (captures error/warn/info) or warn for high-volume apps. Never debug/trace in production."},{"question":"What is the difference between error and fatal?","answer":"Error: operation failed but app can continue. Fatal: app cannot continue (exits or crashes)."},{"question":"What is the difference between debug and trace?","answer":"Debug: detailed diagnostic info (SQL queries, response times). Trace: step-by-step flow (function entry/exit)."},{"question":"What is dynamic log level changing?","answer":"Changing log levels at runtime without restarting — enables debugging production issues on demand."},{"question":"What are per-component log levels?","answer":"Setting different log levels for different modules/services. E.g., debug for db module, warn for http module."},{"question":"What happens if you set log level to warn?","answer":"Only warn, error, and fatal messages are logged. Info, debug, trace are suppressed."},{"question":"Should you log passwords or credit cards?","answer":"Never log sensitive data regardless of level. Use redaction to mask sensitive fields."},{"question":"What is a structured log level field?","answer":"The level is a named field in JSON logs (level: \"error\"). Enables filtering, alerting, and aggregation by severity."},{"question":"What is ansi-colorized log output?","answer":"Logs with color-coded levels for terminal readability (red=error, yellow=warn, green=info, gray=debug)."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Log Levels</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ff4444\" stroke=\"#ff4444\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">FATAL</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">System down</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">ERROR</text><text x=\"65\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Operation failed</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">WARN</text><text x=\"65\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Handled issue</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">INFO</text><text x=\"65\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Normal event</text><rect x=\"10\" y=\"155\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#6c757d\" stroke=\"#6c757d\" stroke-width=\"1\"/><text x=\"65\" y=\"171\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">DEBUG</text><text x=\"65\" y=\"183\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Diagnostics</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"78\" x2=\"150\" y2=\"78\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"108\" x2=\"150\" y2=\"108\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"138\" x2=\"150\" y2=\"138\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"120\" y1=\"168\" x2=\"150\" y2=\"168\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"230\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"275\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Log Levels</text><text x=\"275\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Severity hierarchy: FATAL > ERROR > WARN > INFO > DEBUG > TRACE. Filter noise, control verbosity.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Log Levels: Categorize logs by severity. Control verbosity per environment. Suppress noise, amplify signal.</text></svg>","codeExamples":[{"title":"Setting Log Level in Pino (Node.js)","useCase":"Environment-based level configuration.","code":"const pino = require('pino');\n\nconst logger = pino({\n  level: process.env.LOG_LEVEL || 'info',\n  // In production: LOG_LEVEL=info\n  // In debugging: LOG_LEVEL=debug\n});\n\n// Usage — only logs if level >= configured level\nlogger.fatal('Cannot connect to database');   // always\nlogger.error('Payment failed', { orderId });   // error+\nlogger.warn('Rate limit almost reached');      // warn+\nlogger.info('Server started on port 3000');     // info+\nlogger.debug('SQL query:', query);              // debug+\nlogger.trace('Entering function x');            // trace+\n\n// Check if level is enabled\nif (logger.isLevelEnabled('debug')) {\n  logger.debug({ expensiveData }, 'details');\n}","description":"Pino log level configuration from environment variable with proper level hierarchy."},{"title":"Dynamic Log Level Endpoint (Express)","useCase":"Change levels at runtime.","code":"// POST /admin/loglevel with { level: 'debug' }\napp.post('/admin/loglevel', isAdmin, (req, res) => {\n  const { level } = req.body;\n  const valid = ['fatal','error','warn','info',\n                 'debug','trace'];\n\n  if (!valid.includes(level)) {\n    return res.status(400).json({\n      error: `Invalid level. Valid: ${valid.join(', ')}`\n    });\n  }\n\n  logger.level = level;\n  logger.warn({ level }, 'Log level changed dynamically');\n  res.json({ message: `Log level changed to ${level}` });\n});\n\n// GET /admin/loglevel — view current level\napp.get('/admin/loglevel', isAdmin, (req, res) => {\n  res.json({ currentLevel: logger.level });\n});","description":"Dynamic log level endpoint enables production debugging without restarting the process."},{"title":"Per-Component Log Levels with Child Loggers","useCase":"Different levels for different modules.","code":"const baseLogger = require('pino')({\n  level: process.env.LOG_LEVEL || 'info'\n});\n\n// Database module — more verbose\nconst dbLogger = baseLogger.child({\n  module: 'db'\n}, { level: process.env.DB_LOG_LEVEL || 'debug' });\n\n// HTTP module — less verbose\nconst httpLogger = baseLogger.child({\n  module: 'http'\n}, { level: 'warn' });\n\n// Usage\ndbLogger.debug('Executing query:', query); // logged\nhttpLogger.debug('Request headers:', headers); // suppressed\nhttpLogger.warn('Slow request:', duration); // logged\n\n// Set environment:\n// LOG_LEVEL=info DB_LOG_LEVEL=debug","description":"Per-component log levels let you filter noise at the module level while keeping others quiet."},{"title":"Log Level Filtering in Production","useCase":"Don\\'t log sensitive debug data.","code":"function logUserEvent(event, user, details) {\n  const logData = {\n    event,\n    userId: user.id,\n    role: user.role,\n  };\n\n  // NEVER log passwords, credit cards, tokens\n  // Always use info for business events\n  logger.info(logData, 'User event: ' + event);\n\n  // Debug: add details (only in debug mode)\n  if (logger.isLevelEnabled('debug')) {\n    logger.debug({ ...logData, details },\n      'User event with details');\n  }\n}\n\n// Redact sensitive fields automatically\nconst logger = pino({\n  redact: ['password', 'token', 'ssn',\n           'creditCard', 'authorization'],\n});","description":"Use log level checks and pino redact to prevent sensitive data exposure in production logs."},{"title":"Structured Log Level Field with Winston","useCase":"Level as searchable field.","code":"const winston = require('winston');\n\nconst logger = winston.createLogger({\n  levels: {\n    fatal: 0, error: 1, warn: 2, info: 3,\n    debug: 4, trace: 5\n  },\n  level: 'info',\n  format: winston.format.combine(\n    winston.format.timestamp(),\n    winston.format.json()\n  ),\n  transports: [\n    new winston.transports.Console(),\n    new winston.transports.File({\n      filename: 'logs/errors.log', level: 'error'\n    })\n  ]\n});\n\n// JSON output includes level as field\nlogger.warn('Disk space low', { freeSpace: '5GB' });\n// {\"level\":\"warn\",\"msg\":\"Disk space low\",\n//  \"freeSpace\":\"5GB\",\"timestamp\":\"...\"}","description":"Log level becomes a searchable JSON field, enabling aggregation and filtering in log platforms."}],"mcqQuestions":[{"question":"What is the most severe log level?","options":["error","fatal","warn","info"],"answer":1,"explanation":"Fatal is the most severe — the application cannot continue and will exit."},{"question":"What log level should production run at?","options":["debug","trace","info","fatal"],"answer":2,"explanation":"Production should run at info level — captures errors, warnings, and informational events."},{"question":"If log level is set to warn, which levels are logged?","options":["warn only","warn, error, fatal","info, warn, error","all levels"],"answer":1,"explanation":"Setting level to warn includes warn, error, and fatal (levels at or above severity)."},{"question":"What is the difference between debug and trace?","options":["Same thing","Debug is diagnostic, trace is step-by-step flow","Trace is for testing","Debug is for errors"],"answer":1,"explanation":"Debug logs detailed diagnostics; trace logs execution flow step-by-step."},{"question":"What is dynamic log level changing?","options":["Changing levels in code at compile time","Changing levels at runtime without restart","Automatic level adjustment","Level changes per environment"],"answer":1,"explanation":"Dynamic level changing adjusts verbosity at runtime — no restart needed."},{"question":"What should be redacted from logs?","options":["User IDs","Passwords and tokens","Error messages","Timestamps"],"answer":1,"explanation":"Sensitive data like passwords, tokens, and PII must be redacted from logs."},{"question":"Log Levels — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Log Levels — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Log Levels — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Log Levels — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["logging"]["log-shipping"] = {"id":"log-shipping","title":"Log Shipping","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Log shipping is the process of reliably transferring log data from source servers to a centralized log management platform.","Key requirements: reliability (no data loss during network failures), low latency (near real-time delivery), low resource usage (CPU/memory/network), encryption (TLS for in-transit security).","Popular shippers: Filebeat (Elastic), Fluentbit/Fluentd (CNCF), Vector (Datadog), Logstash (heavy), rsyslog (syslog), Promtail (Loki).","Shipping patterns: tail-based (follow log file), event-based (receive from application), sidecar (containerized environments), agentless (syslog/HTTP)."],"laymanDefinition":"Log shipping is like a fleet of delivery trucks for a warehouse. Each truck (shipper) is stationed at a factory (server). When logs pile up (truck loads), the driver drives to the central warehouse (log platform). If the highway is blocked (network failure), the truck waits and tries again. The trucks are small and efficient — they don't slow down the factory.","deepDive":[{"heading":"Filebeat (Lightweight Shipper)","text":"Elastic\\'s Go-based log shipper. Low memory footprint (~20MB). Reads log files, adds metadata (hostname, kubernetes fields), sends to Elasticsearch or Logstash. Features: multiline handling (stack traces), file rotation awareness, backpressure handling, TLS support. Best for: shipping to ELK stack. Under 15MB binary size."},{"heading":"Fluentd vs Fluentbit","text":"Fluentd: Ruby/C, full-featured, ~60MB, extensive plugin ecosystem (500+), supports buffering. Fluentbit: C, ultra-lightweight (~450KB binary), designed for edge/IoT and containers. Fluentbit is the preferred choice for Kubernetes sidecars and resource-constrained environments. Fluentd for complex routing and transformation pipelines."},{"heading":"Shipping Reliability Mechanisms","text":"Buffering: store logs on disk temporarily if destination unreachable. Retry with exponential backoff. Acknowledgements: wait for destination to confirm receipt before discarding from buffer. Resilience: shipper should not crash or lose data if destination is down for hours. Guaranteed delivery: at-least-once semantics (may duplicate, never lose)."},{"heading":"TLS Encryption and Authentication","text":"Logs may contain sensitive data — always encrypt in transit. Shipper connects to destination over TLS. Mutual TLS (mTLS): both sides authenticate with certificates. API key authentication: simpler alternative, suitable for SaaS log platforms (Datadog, Logz.io). Network segmentation: shippers in private subnet, log platform in DMZ."},{"heading":"Kubernetes Log Shipping","text":"DaemonSet: one Fluentbit pod per node, collects all pod logs from /var/log/containers. Sidecar: logging container alongside app container — good for apps that log to files instead of stdout. Multiple outputs: send to both Elasticsearch (operations) and S3 (archive). Metadata enrichment: add pod name, namespace, container name, Kubernetes labels."}],"interviewAnswer":"Log shipping is the critical first mile of your logging pipeline. Choose a lightweight shipper (Filebeat, Fluentbit) for production. Always buffer logs locally to prevent data loss during network outages. Enable TLS encryption. In Kubernetes, use a DaemonSet shipper for node-level collection. Test for data loss scenarios: kill the shipper, restart it, verify no logs are lost.","interviewQuestions":[{"question":"What is log shipping?","answer":"Reliably transferring log data from source servers to a centralized log management platform."},{"question":"What is Filebeat?","answer":"A lightweight, Go-based log shipper from Elastic. Low memory, high performance, integrates with ELK."},{"question":"What is the difference between Fluentd and Fluentbit?","answer":"Fluentd: full-featured, plugin-rich, larger (~60MB). Fluentbit: ultra-lightweight (~450KB), ideal for edge/Kubernetes."},{"question":"How do shippers handle network failures?","answer":"Buffering: store logs on disk, retry with exponential backoff when the destination becomes available."},{"question":"What is a DaemonSet in Kubernetes logging?","answer":"A DaemonSet runs one log shipper pod per node, collecting logs from all pods on that node."},{"question":"Should logs be encrypted during shipping?","answer":"Yes. Always use TLS for log shipping — logs may contain sensitive data."},{"question":"What is a sidecar log shipper?","answer":"A logging container alongside the app container in the same pod — intercepts log files or stdout."},{"question":"What is Promtail?","answer":"The log shipper for Grafana Loki — designed for Kubernetes with service discovery and label metadata."},{"question":"What is the data loss guarantee of most shippers?","answer":"At-least-once delivery — logs may be duplicated but will not be lost (with buffering configured)."},{"question":"What metadata do shippers add?","answer":"Hostname, service name, Kubernetes pod/namespace/container, Docker container ID, file path."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Log Shipping</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Source</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Application logs</text><line x1=\"120\" y1=\"48\" x2=\"150\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"215\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Shipper</text><text x=\"215\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Filebeat/Fluentbit</text><line x1=\"160\" y1=\"60\" x2=\"160\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"65\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Buffer</text><text x=\"65\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Disk buffer</text><line x1=\"120\" y1=\"83\" x2=\"150\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"70\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"215\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">TLS Encrypt</text><text x=\"215\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Secure transport</text><line x1=\"160\" y1=\"95\" x2=\"160\" y2=\"110\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"105\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"65\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Network</text><text x=\"65\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Kafka/HTTP</text><line x1=\"120\" y1=\"118\" x2=\"150\" y2=\"118\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"160\" y=\"105\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"215\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Destination</text><text x=\"215\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Elasticsearch/Loki</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Log Shipping</text><text x=\"385\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Reliable transfer: Buffer -> Encrypt -> Transport -> Deliver. No data loss. Real-time.</text><text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Log Shipping: Reliably transport logs from source to centralized platform with buffering and encryption.</text></svg>","codeExamples":[{"title":"Filebeat Configuration (Elastic)","useCase":"Lightweight log shipping to Elasticsearch.","code":"# filebeat.yml\nfilebeat.inputs:\n- type: filestream\n  enabled: true\n  paths:\n    - /var/log/myapp/*.json\n    - /var/log/nginx/access.log\n  multiline:\n    type: pattern\n    pattern: '^\\['\n    negate: true\n    match: after\n\nfilebeat.config.modules:\n  path: ${path.config}/modules.d/*.yml\n  reload.enabled: true\n\noutput.elasticsearch:\n  hosts: [\"https://elasticsearch:9200\"]\n  username: \"filebeat_writer\"\n  password: \"${ES_PASSWORD}\"\n  ssl.verification_mode: certificate\n\nlogging.level: warn","description":"Filebeat configuration for shipping JSON and Nginx access logs to Elasticsearch with TLS."},{"title":"Fluentbit Configuration (Kubernetes DaemonSet)","useCase":"Kubernetes-native log shipping.","code":"# fluentbit-config.yaml\napiVersion: v1\nkind: ConfigMap\nmetadata:\n  name: fluentbit-config\ndata:\n  fluent-bit.conf: |\n    [SERVICE]\n        Flush 1\n        Log_Level info\n        Parsers_File parsers.conf\n\n    [INPUT]\n        Name tail\n        Path /var/log/containers/*.log\n        multiline.parser docker, cri\n        Tag kube.*\n        Mem_Buf_Limit 50MB\n        Skip_Long_Lines On\n\n    [FILTER]\n        Name kubernetes\n        Match kube.*\n        Merge_Log On\n        K8S-Logging.Parser On\n\n    [OUTPUT]\n        Name es\n        Match kube.*\n        Host elasticsearch\n        Port 9200\n        Logstash_Format On\n        Retry_Limit 6\n        tls On\n        tls.verify Off","description":"Fluentbit DaemonSet configuration for Kubernetes — collects all pod logs with metadata enrichment."},{"title":"Vector (Datadog) Log Shipping","useCase":"Modern, high-performance shipper.","code":"# vector.toml\n[sources.myapp_logs]\ntype = \"file\"\ninclude = [\"/var/log/myapp/*.json\"]\nread_from = \"beginning\"\n\n[transforms.parse_json]\ntype = \"json_parser\"\ninputs = [\"myapp_logs\"]\nfield = \"message\"\ndrop_invalid = true\n\n[transforms.add_fields]\ntype = \"remap\"\ninputs = [\"parse_json\"]\nsource = '''\n  .environment = \"production\"\n  .service = \"myapp\"\n  .hostname = get_hostname!()\n'''\n\n[sinks.elasticsearch]\ntype = \"elasticsearch\"\ninputs = [\"add_fields\"]\nendpoints = [\"https://elasticsearch:9200\"]\nauth.strategy = \"basic\"\nauth.user = \"vector\"\nauth.password = \"${ES_PASS}\"\nbulk.index = \"myapp-%Y-%m-%d\"\nbuffer.max_events = 5000\nbuffer.when_full = \"block\"","description":"Vector provides a unified pipeline for log collection, transformation, and shipping with buffering."},{"title":"Log Shipping with Buffer (Node.js + Bull Queue)","useCase":"Application-level reliable shipping.","code":"const Queue = require('bull');\nconst logQueue = new Queue('log-shipping', {\n  redis: { host: 'redis' },\n  defaultJobOptions: {\n    attempts: 10,\n    backoff: { type: 'exponential', delay: 2000 }\n  }\n});\n\n// Producer: add log to queue\nasync function shipLog(entry) {\n  await logQueue.add(entry);\n}\n\n// Consumer: send to log platform\nlogQueue.process(async (job) => {\n  const response = await fetch(\n    'https://logs.example.com/_bulk', {\n    method: 'POST',\n    body: JSON.stringify(job.data),\n    headers: {\n      'Content-Type': 'application/json',\n      'Authorization': `Bearer ${LOG_TOKEN}`\n    }\n  });\n\n  if (!response.ok) {\n    throw new Error('Ship failed'); // retry\n  }\n});","description":"Bull queue provides application-level log buffering with retries, backoff, and persistence."},{"title":"Promtail for Grafana Loki","useCase":"Kubernetes log shipping to Loki.","code":"# promtail.yaml\nserver:\n  http_listen_port: 3101\n\npositions:\n  filename: /var/log/positions.yaml\n\nclients:\n  - url: http://loki:3100/loki/api/v1/push\n\nscrape_configs:\n- job_name: kubernetes-pods\n  kubernetes_sd_configs:\n  - role: pod\n  pipeline_stages:\n  - docker: {}\n  - cri: {}\n  - regex:\n      expression: '^(?P<namespace>\\S+)\n        (?P<pod_name>\\S+)\n        (?P<container_name>\\S+)\n        .*'\n  - labels:\n      namespace:\n      pod_name:\n      container_name:","description":"Promtail auto-discovers Kubernetes pods and ships logs with label metadata to Grafana Loki."}],"mcqQuestions":[{"question":"What is a log shipper?","options":["A log database","An agent that reliably transfers logs to a central platform","A log visualizer","A log parser"],"answer":1,"explanation":"A log shipper is an agent that collects and reliably transfers logs from source to destination."},{"question":"Which shipper is ultra-lightweight (~450KB)?","options":["Filebeat","Fluentbit","Logstash","Vector"],"answer":1,"explanation":"Fluentbit is written in C and designed for resource-constrained environments."},{"question":"How do shippers handle network failures?","options":["Stop logging","Buffer logs and retry","Delete old logs","Switch to file storage"],"answer":1,"explanation":"Shippers buffer logs to disk and retry with exponential backoff when the destination is down."},{"question":"What is a DaemonSet in Kubernetes logging?","options":["A pod per deployment","A pod per node collecting all node logs","A sidecar per pod","A standalone service"],"answer":1,"explanation":"DaemonSet runs one shipper per node to collect logs from all pods on that node."},{"question":"What protocol should log shipping use?","options":["HTTP","TLS/HTTPS","FTP","SMTP"],"answer":1,"explanation":"Log shipping should use TLS encryption to protect sensitive data in transit."},{"question":"What delivery guarantee do shippers provide?","options":["Exactly-once","At-least-once","At-most-once","Best-effort"],"answer":1,"explanation":"Most shippers provide at-least-once delivery — logs may duplicate but will not be lost."},{"question":"Log Shipping — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Log Shipping — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Log Shipping — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Log Shipping — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};